/**
 * Reset Password OTP Page
 * 
 * Handles OTP verification step in password reset flow. Validates 6-digit
 * OTP codes sent to user's email and proceeds to password change step.
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, useLocation } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { authService } from '@/features/auth/services';
import { maskEmail } from '@/shared/utils/format-utils.js';
import { createOtpSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { LanguageSelector } from '@/shared/components';
import '/styles/index.css';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';

const ResetPasswordOTP = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;

  const isMobile = windowWidth <= 480;
  const isTablet = windowWidth <= 768;
  const isSmallMobile = windowWidth <= 360;


  const [otp, setOtp] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [email, setEmail] = useState('');

  useEffect(() => {
    if (location.state?.email) {
      setEmail(location.state.email);
    } else {
      showError(t('emailNotProvided', { ns: 'auth' }));
      navigate('/forgot-password');
    }
  }, [location, navigate, showError, t]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    const schema = createOtpSchema(t);
    const validation = schema.safeParse({ otp });

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseEnterValidOTP', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const { otp: validatedOtp } = validation.data;
    setFormErrors({});
    setOtp(validatedOtp);

    setLoading(true);
    setError('');

    try {
      const userId = sessionStorage.getItem('passwordResetUserId');

      if (!userId) {
        throw new Error(t('sessionExpired', { ns: 'auth' }));
      }

      // Verify OTP via API before proceeding
      const resp = await authService.confirmPasswordResetOTP(validatedOtp, userId);

      // Check for successful response (code '00' indicates success)
      if (resp?.code === '00') {
        // Store the validated OTP in session storage for the reset password page
        sessionStorage.setItem('passwordResetOTP', validatedOtp);
        setFormErrors({});

        // Navigate to reset password page with all required data
        navigate('/reset-password', {
          state: {
            email,
            otp: validatedOtp,
            flow: 'password-reset',
            userId: userId // Explicitly pass userId in the state
          },
          replace: true // Replace current entry in history
        });
      } else {
        throw new Error(resp?.message || t('invalidOrExpiredOTP', { ns: 'auth' }));
      }
    } catch (err) {
      setError(err.message || t('failedToVerifyOTP', { ns: 'auth' }));
      showError(err.message || t('failedToVerifyOTP', { ns: 'auth' }));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit} style={{
        paddingTop: isSmallMobile ? '52px' : isMobile ? '56px' : isTablet ? '60px' : '48px'
      }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1,
            maxWidth: isSmallMobile ? '100px' : isMobile ? '120px' : isTablet ? '160px' : '180px',
            marginTop: isSmallMobile ? '2px' : isMobile ? '4px' : isTablet ? '8px' : '0',
            marginBottom: isSmallMobile ? '16px' : isMobile ? '20px' : isTablet ? '24px' : '32px'
          }}
        />

        <h2 style={{ marginBottom: '10px' }}>{t('verifyYourIdentity', { ns: 'auth' })}</h2>
        <p style={{
          textAlign: 'center',
          marginBottom: '30px',
          color: '#4b5563',
          fontSize: '0.95rem'
        }}>
          {t('enterOtpToContinue', { ns: 'auth' })}
        </p>

        {error && <div className="error-message">{error}</div>}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-shield-halved"></i></span>
          <input
            type="text"
            value={otp}
            onChange={(e) => {
              const sanitized = e.target.value.replace(/\D/g, '').slice(0, 6);
              setOtp(sanitized);
              if (error) {
                setError('');
              }
              if (formErrors.otp) {
                setFormErrors((prev) => {
                  const next = { ...prev };
                  delete next.otp;
                  return next;
                });
              }
            }}
            placeholder="••••••"
            maxLength={6}
            disabled={loading}
            required
            style={{
              marginBottom: 0,
              letterSpacing: '8px',
              textAlign: 'center',
              fontSize: '1.2rem',
              fontFamily: 'monospace',
              padding: '12px 12px 12px 40px',
              borderColor: error ? '#ef4444' : undefined,
              '::placeholder': {
                color: '#9ca3af',
                fontSize: '0.8rem',
                opacity: 0.8,
                letterSpacing: 'normal',
                position: 'relative',
                left: '-8px' // Adjust to center the dots
              }
            }}
            className="form-input"
          />
        </div>
        {formErrors.otp && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-8px', marginBottom: '12px', textAlign: 'center' }}>
            {formErrors.otp}
          </p>
        )}

        <button
          type="submit"
          className="primary-button"
          disabled={loading || otp.length !== 6}
          style={{ backgroundColor: '#004895' }}
        >
          {loading ? t('verifying', { ns: 'auth' }) : t('continue', { ns: 'auth' })}
        </button>

        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{
            width: '100%',
            backgroundColor: '#23bd00',
            marginTop: '10px'
          }}
          className="primary-button"
        >
          {t('backToLogin', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
};

export default ResetPasswordOTP;
